import React, { useEffect, useMemo, useState, useCallback } from 'react';
import {
  Alert,
  ActivityIndicator,
  Button,
  Platform,
  SafeAreaView,
  StyleSheet,
  Text,
  TextInput,
  View,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics, { BiometryTypes } from 'react-native-biometrics';

const AUTH_FLAG_KEY = 'auth:authenticated';
const DEMO_PASSWORD = 'password123';

function AuthGate() {
  const [booting, setBooting] = useState(true);
  const [authenticated, setAuthenticated] = useState(false);

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        const flag = await AsyncStorage.getItem(AUTH_FLAG_KEY);
        if (mounted && flag === 'true') setAuthenticated(true);
      } finally {
        if (mounted) setBooting(false);
      }
    })();
    return () => {
      mounted = false;
    };
  }, []);

  const onAuthenticated = useCallback(async () => {
    await AsyncStorage.setItem(AUTH_FLAG_KEY, 'true');
    setAuthenticated(true);
  }, []);

  const onLogout = useCallback(async () => {
    await AsyncStorage.removeItem(AUTH_FLAG_KEY);
    setAuthenticated(false);
  }, []);

  if (booting) return <Splash />;
  if (authenticated) return <HomeScreen onLogout={onLogout} />;
  return <LoginScreen onAuthenticated={onAuthenticated} />;
}

function Splash() {
  return (
    <SafeAreaView style={styles.center}>
      <ActivityIndicator size="large" />
      <Text style={styles.muted}>Loading…</Text>
    </SafeAreaView>
  );
}

function HomeScreen({ onLogout }) {
  return (
    <SafeAreaView style={styles.container}>
      <Text style={styles.title}>Home</Text>
      <Text style={styles.subtitle}>You are authenticated.</Text>
      <View style={styles.spacer} />
      <Button title="Logout" onPress={onLogout} />
    </SafeAreaView>
  );
}

function LoginScreen({ onAuthenticated }) {
  const rnBiometrics = useMemo(() => new ReactNativeBiometrics(), []);
  const [checking, setChecking] = useState(true);
  const [biometryType, setBiometryType] = useState(null);
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);

  const [password, setPassword] = useState('');
  const [submitting, setSubmitting] = useState(false);

  const biometricLabel = useMemo(() => {
    if (biometryType === BiometryTypes.FaceID) return 'Face ID';
    if (biometryType === BiometryTypes.TouchID) return 'Touch ID';
    if (biometryType === BiometryTypes.Biometrics) return 'Biometrics';
    return 'Biometrics';
  }, [biometryType]);

  const checkBiometrics = useCallback(async () => {
    setChecking(true);
    try {
      const { available, biometryType: type } = await rnBiometrics.isSensorAvailable();
      setBiometricsAvailable(!!available);
      setBiometryType(type ?? null);
    } catch (e) {
      setBiometricsAvailable(false);
      setBiometryType(null);
    } finally {
      setChecking(false);
    }
  }, [rnBiometrics]);

  useEffect(() => {
    checkBiometrics();
  }, [checkBiometrics]);

  const promptBiometric = useCallback(async () => {
    setSubmitting(true);
    try {
      const promptMessage =
        Platform.OS === 'ios'
          ? `Authenticate with ${biometricLabel}`
          : 'Authenticate';

      const result = await rnBiometrics.simplePrompt({
        promptMessage,
        cancelButtonText: 'Cancel',
      });

      if (result?.success) {
        await onAuthenticated();
      } else {
        Alert.alert('Authentication failed', 'Please try again or use password.');
      }
    } catch (e) {
      Alert.alert('Authentication error', 'Please use password to continue.');
    } finally {
      setSubmitting(false);
    }
  }, [rnBiometrics, biometricLabel, onAuthenticated]);

  const submitPassword = useCallback(async () => {
    setSubmitting(true);
    try {
      if (password === DEMO_PASSWORD) {
        await onAuthenticated();
      } else {
        Alert.alert('Incorrect password', 'Please try again.');
      }
    } finally {
      setSubmitting(false);
    }
  }, [password, onAuthenticated]);

  return (
    <SafeAreaView style={styles.container}>
      <Text style={styles.title}>Login</Text>

      <View style={styles.card}>
        {checking ? (
          <View style={styles.centerRow}>
            <ActivityIndicator />
            <Text style={styles.muted}>Checking biometrics…</Text>
          </View>
        ) : biometricsAvailable ? (
          <>
            <Text style={styles.subtitle}>Use {biometricLabel} to continue.</Text>
            <View style={styles.spacerSm} />
            <Button
              title={`Continue with ${biometricLabel}`}
              onPress={promptBiometric}
              disabled={submitting}
            />
            <View style={styles.divider} />
            <Text style={styles.muted}>Or use password:</Text>
          </>
        ) : (
          <>
            <Text style={styles.subtitle}>Biometrics not available. Use password.</Text>
            <View style={styles.spacerSm} />
          </>
        )}

        <View style={styles.spacerSm} />
        <TextInput
          value={password}
          onChangeText={setPassword}
          placeholder="Password"
          secureTextEntry
          autoCapitalize="none"
          autoCorrect={false}
          editable={!submitting}
          style={styles.input}
          returnKeyType="done"
          onSubmitEditing={submitPassword}
        />
        <View style={styles.spacerSm} />
        <Button title="Login with Password" onPress={submitPassword} disabled={submitting} />
      </View>

      {biometricsAvailable ? (
        <View style={styles.footer}>
          <Button title="Re-check biometrics" onPress={checkBiometrics} disabled={submitting} />
        </View>
      ) : null}

      <View style={styles.footerNote}>
        <Text style={styles.note}>
          Demo password: {DEMO_PASSWORD}
        </Text>
      </View>
    </SafeAreaView>
  );
}

export default function App() {
  return <AuthGate />;
}

